"use strict";parserFactory.register("comrademao.com",()=>new ComrademaoParser);class ComrademaoParser extends Parser{constructor(){super()}disabled(){return UIText.Warning.parserDisabledNotification}populateUIImpl(){document.getElementById("removeOriginalRow").hidden=!1}getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,ComrademaoParser.extractPartialChapterList,ComrademaoParser.getUrlsOfTocPages,t).then(e=>e.reverse())}static getUrlsOfTocPages(e){let t=[];if(null!=e.querySelector("nav.pagination")){let r=[...e.querySelectorAll("a.page-numbers:not(.next)")].map(e=>e.href);if(0<r.length){let e=r[r.length-1],a=e.lastIndexOf("/",e.length-2),n=e.substring(0,a+1),l=parseInt(e.substring(a+1));if(1<l)for(let e=2;e<=l;++e)t.push(`${n}${e}/`)}}return t}static extractPartialChapterList(e){let t=e.querySelector("table.table");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector(".site-main article")}extractTitleImpl(e){return e.querySelector(".entry-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"button, nav, div#comments"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"#thumbnail")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#Description")]}}